import{_ as t,o as a,c as o,ag as l}from"./chunks/framework.DEs8X8sU.js";const g=JSON.parse('{"title":"Googleレビュー連携","description":"","frontmatter":{"title":"Googleレビュー連携"},"headers":[],"relativePath":"tenant/20-google-review.md","filePath":"tenant/20-google-review.md"}'),i={name:"tenant/20-google-review.md"};function r(d,e,n,h,s,_){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="_20-googleレビュー連携" tabindex="-1">20. Googleレビュー連携 <a class="header-anchor" href="#_20-googleレビュー連携" aria-label="Permalink to &quot;20. Googleレビュー連携&quot;">​</a></h1><p>Googleレビュー連携では、満足度の高いお客様をGoogleレビューへ案内し、店舗の評価向上につなげます。</p><h2 id="基本の流れ" tabindex="-1">基本の流れ <a class="header-anchor" href="#基本の流れ" aria-label="Permalink to &quot;基本の流れ&quot;">​</a></h2><ol><li>店舗設定でGoogleレビュー連携を確認します。</li><li>レビュー案内の表示内容を設定します。</li><li>会計後やセルフオーダー画面で満足度評価を受け付けます。</li><li>高評価のお客様をGoogleレビューへ案内します。</li><li>低評価のお客様には店舗内で改善につなげます。</li></ol><h2 id="運用時の注意" tabindex="-1">運用時の注意 <a class="header-anchor" href="#運用時の注意" aria-label="Permalink to &quot;運用時の注意&quot;">​</a></h2><ul><li>レビュー投稿を強制しないでください。</li><li>見返りを条件にレビューを依頼しないでください。</li><li>低評価を隠す目的で不適切な誘導を行わないでください。</li><li>お客様の声は、接客やメニュー改善の参考にしてください。</li></ul><h2 id="満足度評価" tabindex="-1">満足度評価 <a class="header-anchor" href="#満足度評価" aria-label="Permalink to &quot;満足度評価&quot;">​</a></h2><p>満足度評価は、店舗内での改善にも役立ちます。低評価が続く場合は、時間帯、商品、スタッフ体制などを確認してください。</p><p>低評価（1〜2）を選んだお客様には、差し支えない範囲で気になった点（提供時間／味／温度／量／注文内容／接客／清潔感／価格 など）をお伺いする画面が表示されます。任意入力で、お客様に負担をかけない設計です。</p><p>集計結果は管理画面 → レポート → 満足度分析 で確認できます（詳しくは「13. レポート」をご覧ください）。集計は店舗改善のために活用してください。低評価を「外部レビューに出ないようにする」ためではなく、品目・時間帯・運営の見直しに使う仕組みです。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>レビュー案内が出ない</td><td>連携設定と表示タイミングを確認してください。</td></tr><tr><td>リンク先が違う</td><td>GoogleビジネスプロフィールのURLを確認してください。</td></tr><tr><td>評価が偏る</td><td>案内文や表示タイミングを見直してください。</td></tr></tbody></table>',12)])])}const p=t(i,[["render",r]]);export{g as __pageData,p as default};
